import sqlite3
import hashlib
import os


def initialize_database(db_path="legacy_users.db"):
    """Initialize the database with a users table and sample data for testing."""
    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT UNIQUE NOT NULL,
            password_hash TEXT NOT NULL,
            salt TEXT NOT NULL,
            is_active INTEGER DEFAULT 1
        )
    """)
    conn.commit()
    conn.close()


def hash_password(password, salt=None):
    """Hash a password with a salt using SHA-256."""
    if salt is None:
        salt = os.urandom(32).hex()
    password_hash = hashlib.sha256((salt + password).encode('utf-8')).hexdigest()
    return password_hash, salt


def create_user(username, password, db_path="legacy_users.db"):
    """Create a new user in the database."""
    password_hash, salt = hash_password(password)
    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()
    try:
        # Using parameterized query to prevent SQL injection
        cursor.execute(
            "INSERT INTO users (username, password_hash, salt) VALUES (?, ?, ?)",
            (username, password_hash, salt)
        )
        conn.commit()
        print(f"User '{username}' created successfully.")
        return True
    except sqlite3.IntegrityError:
        print(f"Error: User '{username}' already exists.")
        return False
    finally:
        conn.close()


def login(username, password, db_path="legacy_users.db"):
    """
    Authenticate a user by checking the provided username and password
    against the users table in the legacy database.

    Uses parameterized queries to prevent SQL injection.

    Args:
        username: The username to authenticate.
        password: The plaintext password to verify.
        db_path: Path to the SQLite database file.

    Returns:
        dict: User info dict on success, None on failure.
    """
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    cursor = conn.cursor()

    try:
        # SECURE: Using parameterized query with ? placeholders
        # This prevents SQL injection by letting sqlite3 handle escaping
        cursor.execute(
            "SELECT id, username, password_hash, salt, is_active FROM users WHERE username = ?",
            (username,)
        )

        user_row = cursor.fetchone()

        if user_row is None:
            print("Login failed: Invalid username or password.")
            return None

        if not user_row["is_active"]:
            print("Login failed: Account is deactivated.")
            return None

        # Verify the password against the stored hash
        stored_hash = user_row["password_hash"]
        stored_salt = user_row["salt"]
        computed_hash, _ = hash_password(password, salt=stored_salt)

        if computed_hash != stored_hash:
            print("Login failed: Invalid username or password.")
            return None

        user_info = {
            "id": user_row["id"],
            "username": user_row["username"],
            "is_active": bool(user_row["is_active"])
        }
        print(f"Login successful. Welcome, {user_info['username']}!")
        return user_info

    finally:
        conn.close()


